function initStickyHeader(){const e=document.getElementById("siteHeader"),d=document.getElementById("sitePreheader"),n=document.getElementById("headerWrapper"),s=document.getElementById("headerPlaceholder");if(!e||!d||!n||!s)return;const r=window.matchMedia("(min-width: 980px)"),t=()=>{const i=r.matches?d.offsetHeight:0,o=n.offsetHeight;s.style.height=`${o}px`,window.scrollY>i?e.classList.add("is-scrolled"):e.classList.remove("is-scrolled")};t(),window.addEventListener("scroll",t,{passive:!0}),window.addEventListener("resize",t)}window.addEventListener("DOMContentLoaded",initStickyHeader);
